import{_ as e,c as o,o as d,ag as r}from"./chunks/framework.Bw-5EFTY.js";const u=JSON.parse('{"title":"Agents Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-core/SPEC.md","filePath":"packages/agent-core/SPEC.md"}'),a={name:"packages/agent-core/SPEC.md"};function c(s,t,n,i,l,h){return d(),o("div",null,t[0]||(t[0]=[r(`<h1 id="agents-specification" tabindex="-1">Agents Specification <a class="header-anchor" href="#agents-specification" aria-label="Permalink to &quot;Agents Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><ul><li>Owns the core Robota agent runtime, tool integration, conversation execution, and plugin-facing agent behavior.</li><li>Defines the canonical agent orchestration surface used by provider and higher-level packages.</li><li>Provides abstract base classes that provider packages and extensions must implement.</li></ul><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Keeps provider-specific transport behavior in provider packages (<code>@robota-sdk/agent-provider-openai</code>, <code>@robota-sdk/agent-provider-anthropic</code>, <code>@robota-sdk/agent-provider-google</code>).</li><li>Keeps package-specific domain contracts owned once and reused through public surfaces.</li><li>Does not own workflow visualization, DAG orchestration, or session persistence (those belong to <code>dag-*</code>, <code>@robota-sdk/agent-sessions</code>).</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><h3 id="layer-structure" tabindex="-1">Layer Structure <a class="header-anchor" href="#layer-structure" aria-label="Permalink to &quot;Layer Structure&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Robota (Facade)</span></span>
<span class="line"><span>  ├── ExecutionService (Orchestrator)</span></span>
<span class="line"><span>  │     ├── AI Provider call (via AIProviders manager)</span></span>
<span class="line"><span>  │     └── Tool execution (via ToolExecutionService)</span></span>
<span class="line"><span>  ├── Manager Layer</span></span>
<span class="line"><span>  │     ├── AIProviders        — provider registration and selection</span></span>
<span class="line"><span>  │     ├── Tools              — tool registry and schema lookup</span></span>
<span class="line"><span>  │     ├── AgentFactory       — agent creation and lifecycle</span></span>
<span class="line"><span>  │     ├── ConversationHistory — session and message storage</span></span>
<span class="line"><span>  │     └── ModuleRegistry     — dynamic module loading</span></span>
<span class="line"><span>  ├── Service Layer</span></span>
<span class="line"><span>  │     ├── ExecutionService        — message handling, LLM calls, response assembly</span></span>
<span class="line"><span>  │     ├── ToolExecutionService    — schema validation, tool lookup, batch execution</span></span>
<span class="line"><span>  │     └── EventService            — unified event emission with ownerPath binding</span></span>
<span class="line"><span>  ├── Permission Layer</span></span>
<span class="line"><span>  │     ├── permission-gate.ts      — evaluatePermission(): 3-step deterministic policy</span></span>
<span class="line"><span>  │     ├── permission-mode.ts      — MODE_POLICY matrix, UNKNOWN_TOOL_FALLBACK</span></span>
<span class="line"><span>  │     └── types.ts                — TPermissionMode, TTrustLevel, TPermissionDecision</span></span>
<span class="line"><span>  ├── Hook Layer</span></span>
<span class="line"><span>  │     ├── hook-runner.ts          — runHooks(): shell command hook execution engine</span></span>
<span class="line"><span>  │     └── types.ts                — THookEvent, THooksConfig, IHookInput, IHookResult</span></span>
<span class="line"><span>  └── Plugin Layer (1 built-in + 8 external @robota-sdk/agent-plugin-* packages)</span></span>
<span class="line"><span>        ├── EventEmitterPlugin           (built-in — event coordination)</span></span>
<span class="line"><span>        └── External plugins (per @robota-sdk/agent-plugin-*):</span></span>
<span class="line"><span>              conversation-history, logging, usage, performance,</span></span>
<span class="line"><span>              execution-analytics, error-handling, limits, webhook</span></span></code></pre></div><h3 id="design-patterns" tabindex="-1">Design Patterns <a class="header-anchor" href="#design-patterns" aria-label="Permalink to &quot;Design Patterns&quot;">​</a></h3><ul><li><strong>Facade</strong>: <code>Robota</code> is the single entry point, hiding manager/service/plugin complexity.</li><li><strong>Template Method</strong>: <code>AbstractAgent</code> defines lifecycle hooks (<code>beforeRun</code>, <code>afterRun</code>, <code>onError</code>).</li><li><strong>Strategy</strong>: Event services, storage strategies, error handling strategies are interchangeable.</li><li><strong>Registry</strong>: <code>ToolRegistry</code> and <code>ModuleRegistry</code> for central resource management.</li><li><strong>Null Object</strong>: <code>SilentLogger</code> and <code>DefaultEventService</code> provide safe no-op defaults.</li><li><strong>Factory</strong>: <code>AgentFactory</code> for agent creation with lifecycle hooks.</li><li><strong>Observer</strong>: <code>EventEmitterPlugin</code> for pub/sub event coordination.</li></ul><h3 id="dependency-injection" tabindex="-1">Dependency Injection <a class="header-anchor" href="#dependency-injection" aria-label="Permalink to &quot;Dependency Injection&quot;">​</a></h3><p>All managers, services, and tools accept dependencies through constructor injection. No global singletons exist. Each <code>Robota</code> instance is completely independent.</p><p>Safe defaults use the Null Object pattern:</p><ul><li><code>SilentLogger</code> for logging (no side effects)</li><li><code>DEFAULT_ABSTRACT_EVENT_SERVICE</code> for events (no-op)</li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is the single source of truth (SSOT) for the following types:</p><table tabindex="0"><thead><tr><th>Type</th><th>Location</th><th>Purpose</th></tr></thead><tbody><tr><td><code>TUniversalMessage</code></td><td><code>interfaces/messages.ts</code></td><td>Canonical message union (User, Assistant, System, Tool)</td></tr><tr><td><code>TUniversalMessageMetadata</code></td><td><code>interfaces/messages.ts</code></td><td>Message metadata record. Values: <code>string | number | boolean | Date | string[] | number[] | Record&lt;string, number&gt;</code> (includes token usage objects)</td></tr><tr><td><code>TUniversalValue</code></td><td><code>interfaces/types.ts</code></td><td>Recursive value type without <code>any</code></td></tr><tr><td><code>TMetadata</code></td><td><code>interfaces/types.ts</code></td><td>Metadata record type</td></tr><tr><td><code>IAgentConfig</code></td><td><code>interfaces/agent.ts</code></td><td>Agent configuration contract</td></tr><tr><td><code>IAIProvider</code></td><td><code>interfaces/provider.ts</code></td><td>Provider integration contract</td></tr><tr><td><code>IToolSchema</code></td><td><code>interfaces/provider.ts</code></td><td>Tool schema contract</td></tr><tr><td><code>TToolParameters</code></td><td><code>interfaces/types.ts</code></td><td>Tool parameter type (re-exported via <code>interfaces/tool.ts</code>)</td></tr><tr><td><code>IEventService</code></td><td><code>event-service/interfaces.ts</code></td><td>Event emission contract</td></tr><tr><td><code>IOwnerPathSegment</code></td><td><code>event-service/interfaces.ts</code></td><td>Execution path tracking</td></tr><tr><td><code>RobotaError</code></td><td><code>utils/errors.ts</code></td><td>Base error hierarchy</td></tr><tr><td><code>TTextDeltaCallback</code></td><td><code>interfaces/provider.ts</code></td><td>Streaming text delta callback <code>(delta: string) =&gt; void</code></td></tr><tr><td><code>TPermissionMode</code></td><td><code>permissions/types.ts</code></td><td>Permission modes: plan, default, acceptEdits, bypassPermissions</td></tr><tr><td><code>TTrustLevel</code></td><td><code>permissions/types.ts</code></td><td>Friendly trust aliases: safe, moderate, full</td></tr><tr><td><code>TPermissionDecision</code></td><td><code>permissions/types.ts</code></td><td>Evaluation outcome: auto, approve, deny</td></tr><tr><td><code>TToolArgs</code></td><td><code>permissions/permission-gate.ts</code></td><td>Tool arguments record for permission matching</td></tr><tr><td><code>IPermissionLists</code></td><td><code>permissions/permission-gate.ts</code></td><td>Allow/deny pattern lists for permission config</td></tr><tr><td><code>TKnownToolName</code></td><td><code>permissions/permission-mode.ts</code></td><td>Known tool names in the permission system</td></tr><tr><td><code>THookEvent</code></td><td><code>hooks/types.ts</code></td><td>Hook lifecycle events: PreToolUse, PostToolUse, PreCompact, PostCompact, SessionStart, Stop</td></tr><tr><td><code>THooksConfig</code></td><td><code>hooks/types.ts</code></td><td>Complete hooks configuration: event to hook groups</td></tr><tr><td><code>IHookGroup</code></td><td><code>hooks/types.ts</code></td><td>Hook group: matcher pattern + hook definitions</td></tr><tr><td><code>IHookDefinition</code></td><td><code>hooks/types.ts</code></td><td>Single hook definition (type: command, command string)</td></tr><tr><td><code>IHookInput</code></td><td><code>hooks/types.ts</code></td><td>Input passed to hook commands via stdin</td></tr><tr><td><code>IHookResult</code></td><td><code>hooks/types.ts</code></td><td>Hook execution result (exitCode, stdout, stderr)</td></tr><tr><td><code>IContextTokenUsage</code></td><td><code>context/types.ts</code></td><td>Token usage from a single API call (input, output, cache tokens)</td></tr><tr><td><code>IContextWindowState</code></td><td><code>context/types.ts</code></td><td>Context window state snapshot (maxTokens, usedTokens, percentage)</td></tr></tbody></table><p>Provider packages import these types. They must not re-declare them.</p><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>Robota</code></td><td>class</td><td>Main agent facade</td></tr><tr><td><code>AbstractAgent</code></td><td>abstract class</td><td>Base agent lifecycle</td></tr><tr><td><code>AbstractAIProvider</code></td><td>abstract class</td><td>Base for provider implementations</td></tr><tr><td><code>AbstractPlugin</code></td><td>abstract class</td><td>Base for plugin extensions</td></tr><tr><td><code>AbstractTool</code></td><td>abstract class</td><td>Base for tool implementations</td></tr><tr><td><code>AbstractExecutor</code></td><td>abstract class</td><td>Base for execution strategies</td></tr><tr><td><code>LocalExecutor</code></td><td>class</td><td>Local provider execution</td></tr></tbody></table><h3 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h3><p>NOTE: <code>ToolRegistry</code>, <code>FunctionTool</code>, <code>createFunctionTool</code>, <code>createZodFunctionTool</code>, and <code>OpenAPITool</code> have been moved to <code>@robota-sdk/agent-tools</code>. <code>MCPTool</code> and <code>RelayMcpTool</code> have been moved to <code>@robota-sdk/agent-tool-mcp</code>.</p><h3 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>evaluatePermission</code></td><td>function</td><td>3-step deterministic policy: deny list, allow list, mode</td></tr><tr><td><code>MODE_POLICY</code></td><td>const</td><td>Permission mode to tool decision matrix</td></tr><tr><td><code>TRUST_TO_MODE</code></td><td>const</td><td>Maps TTrustLevel to TPermissionMode</td></tr><tr><td><code>UNKNOWN_TOOL_FALLBACK</code></td><td>const</td><td>Fallback decisions for unknown tools per mode</td></tr><tr><td><code>TPermissionMode</code></td><td>type</td><td><code>&#39;plan&#39; | &#39;default&#39; | &#39;acceptEdits&#39; | &#39;bypassPermissions&#39;</code></td></tr><tr><td><code>TTrustLevel</code></td><td>type</td><td><code>&#39;safe&#39; | &#39;moderate&#39; | &#39;full&#39;</code></td></tr><tr><td><code>TPermissionDecision</code></td><td>type</td><td><code>&#39;auto&#39; | &#39;approve&#39; | &#39;deny&#39;</code></td></tr><tr><td><code>TToolArgs</code></td><td>type</td><td>Tool arguments record for permission matching</td></tr><tr><td><code>IPermissionLists</code></td><td>type</td><td>Allow/deny pattern lists</td></tr><tr><td><code>TKnownToolName</code></td><td>type</td><td>Known tool names: Bash, Read, Write, Edit, Glob, Grep</td></tr></tbody></table><h3 id="hooks" tabindex="-1">Hooks <a class="header-anchor" href="#hooks" aria-label="Permalink to &quot;Hooks&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>runHooks</code></td><td>function</td><td>Execute shell command hooks for lifecycle events</td></tr><tr><td><code>THookEvent</code></td><td>type</td><td><code>&#39;PreToolUse&#39; | &#39;PostToolUse&#39; | &#39;SessionStart&#39; | &#39;Stop&#39; | &#39;PreCompact&#39; | &#39;PostCompact&#39;</code></td></tr><tr><td><code>THooksConfig</code></td><td>type</td><td>Event to hook group array mapping</td></tr><tr><td><code>IHookGroup</code></td><td>type</td><td>Matcher pattern + hook definitions</td></tr><tr><td><code>IHookDefinition</code></td><td>type</td><td>Single hook definition (command type)</td></tr><tr><td><code>IHookInput</code></td><td>type</td><td>JSON input passed to hooks via stdin</td></tr><tr><td><code>IHookResult</code></td><td>type</td><td>Hook result: exitCode (0=allow, 2=block), stdout, stderr</td></tr></tbody></table><h3 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>TTextDeltaCallback</code></td><td>type</td><td><code>(delta: string) =&gt; void</code> — streaming text callback</td></tr></tbody></table><p>This callback is declared in <code>IChatOptions.onTextDelta</code> and used by providers to emit text chunks during streaming responses.</p><h3 id="context-window-tracking" tabindex="-1">Context Window Tracking <a class="header-anchor" href="#context-window-tracking" aria-label="Permalink to &quot;Context Window Tracking&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>IContextTokenUsage</code></td><td>interface</td><td>Token usage from a single API call (inputTokens, outputTokens, cache)</td></tr><tr><td><code>IContextWindowState</code></td><td>interface</td><td>Context window state snapshot (maxTokens, usedTokens, usedPercentage)</td></tr></tbody></table><p>These types are consumed by <code>@robota-sdk/agent-sessions</code> to track cumulative token usage and context window state across conversation turns.</p><h3 id="managers" tabindex="-1">Managers <a class="header-anchor" href="#managers" aria-label="Permalink to &quot;Managers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>AgentFactory</code></td><td>class</td><td>Agent creation and lifecycle</td></tr><tr><td><code>AgentTemplates</code></td><td>class</td><td>Template-based agent creation</td></tr><tr><td><code>ConversationHistory</code></td><td>class</td><td>History management</td></tr><tr><td><code>ConversationSession</code></td><td>class</td><td>Session management</td></tr></tbody></table><h3 id="services" tabindex="-1">Services <a class="header-anchor" href="#services" aria-label="Permalink to &quot;Services&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>AbstractEventService</code></td><td>abstract class</td><td>Event system base</td></tr><tr><td><code>DefaultEventService</code></td><td>class</td><td>No-op event service</td></tr><tr><td><code>StructuredEventService</code></td><td>class</td><td>Owner-bound events</td></tr><tr><td><code>ObservableEventService</code></td><td>class</td><td>RxJS integration</td></tr><tr><td><code>EventHistoryModule</code></td><td>class</td><td>Event recording</td></tr></tbody></table><h3 id="plugins-1-built-in" tabindex="-1">Plugins (1 built-in) <a class="header-anchor" href="#plugins-1-built-in" aria-label="Permalink to &quot;Plugins (1 built-in)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plugin</th><th>Category</th><th>Description</th></tr></thead><tbody><tr><td><code>EventEmitterPlugin</code></td><td>event_processing</td><td>Event coordination</td></tr></tbody></table><p>8 plugins were extracted to <code>@robota-sdk/agent-plugin-*</code> packages to comply with the agent-core zero-dependency rule. They extend <code>AbstractPlugin</code> (defined here) and are wired by the consuming layer.</p><h2 id="plugin-contract" tabindex="-1">Plugin Contract <a class="header-anchor" href="#plugin-contract" aria-label="Permalink to &quot;Plugin Contract&quot;">​</a></h2><p>Plugins extend <code>AbstractPlugin</code> and implement lifecycle hooks:</p><table tabindex="0"><thead><tr><th>Hook</th><th>Timing</th><th>Purpose</th></tr></thead><tbody><tr><td><code>beforeRun</code></td><td>Before LLM call</td><td>Input transformation, validation</td></tr><tr><td><code>afterRun</code></td><td>After LLM response</td><td>Output processing, recording</td></tr><tr><td><code>onError</code></td><td>On execution error</td><td>Error handling, recovery</td></tr><tr><td><code>onStreamChunk</code></td><td>During streaming</td><td>Chunk processing</td></tr><tr><td><code>beforeToolExecution</code></td><td>Before tool call</td><td>Tool input validation</td></tr><tr><td><code>afterToolExecution</code></td><td>After tool result</td><td>Tool output processing</td></tr></tbody></table><p>Plugins declare <code>category</code> (PluginCategory) and <code>priority</code> (PluginPriority) for execution ordering.</p><h2 id="event-architecture" tabindex="-1">Event Architecture <a class="header-anchor" href="#event-architecture" aria-label="Permalink to &quot;Event Architecture&quot;">​</a></h2><h3 id="event-naming" tabindex="-1">Event Naming <a class="header-anchor" href="#event-naming" aria-label="Permalink to &quot;Event Naming&quot;">​</a></h3><p>Full event names follow the pattern <code>ownerType.localName</code>:</p><table tabindex="0"><thead><tr><th>Prefix</th><th>Owner</th><th>Examples</th></tr></thead><tbody><tr><td><code>execution.*</code></td><td>ExecutionService</td><td><code>execution.start</code>, <code>execution.complete</code></td></tr><tr><td><code>tool.*</code></td><td>ToolExecutionService</td><td><code>tool.execute_start</code>, <code>tool.execute_success</code></td></tr><tr><td><code>agent.*</code></td><td>Robota</td><td><code>agent.completion</code>, <code>agent.created</code></td></tr><tr><td><code>task.*</code></td><td>Task system</td><td><code>task.started</code>, <code>task.completed</code></td></tr><tr><td><code>user.*</code></td><td>User actions</td><td><code>user.input</code></td></tr></tbody></table><h3 id="owner-path-tracking" tabindex="-1">Owner Path Tracking <a class="header-anchor" href="#owner-path-tracking" aria-label="Permalink to &quot;Owner Path Tracking&quot;">​</a></h3><p>Each event carries an <code>ownerPath</code> array of <code>IOwnerPathSegment</code> objects that traces the execution hierarchy:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IOwnerPathSegment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  ownerType</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &#39;agent&#39; | &#39;tool&#39; | &#39;execution&#39;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  ownerId</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Events are bound to their owner via <code>bindWithOwnerPath()</code>.</p><h2 id="permission-system" tabindex="-1">Permission System <a class="header-anchor" href="#permission-system" aria-label="Permalink to &quot;Permission System&quot;">​</a></h2><p>The permission module (<code>src/permissions/</code>) provides a deterministic, three-step policy evaluation for tool calls. It is consumed by <code>@robota-sdk/agent-sessions</code> to gate tool execution before delegating to the actual tool.</p><h3 id="evaluation-algorithm-evaluatepermission" tabindex="-1">Evaluation Algorithm (<code>evaluatePermission</code>) <a class="header-anchor" href="#evaluation-algorithm-evaluatepermission" aria-label="Permalink to &quot;Evaluation Algorithm (\`evaluatePermission\`)&quot;">​</a></h3><ol><li><strong>Deny list match</strong> -- If any deny pattern matches the tool invocation, return <code>&#39;deny&#39;</code>.</li><li><strong>Allow list match</strong> -- If any allow pattern matches, return <code>&#39;auto&#39;</code> (proceed without prompting).</li><li><strong>Mode policy lookup</strong> -- Look up the tool in <code>MODE_POLICY[mode]</code>. If found, return the mapped decision. Otherwise, return <code>UNKNOWN_TOOL_FALLBACK[mode]</code>.</li></ol><h3 id="permission-modes" tabindex="-1">Permission Modes <a class="header-anchor" href="#permission-modes" aria-label="Permalink to &quot;Permission Modes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Read tools</th><th>Write tools</th><th>Bash</th></tr></thead><tbody><tr><td><code>plan</code></td><td>auto</td><td>deny</td><td>deny</td></tr><tr><td><code>default</code></td><td>auto</td><td>approve (prompt)</td><td>approve (prompt)</td></tr><tr><td><code>acceptEdits</code></td><td>auto</td><td>auto</td><td>approve (prompt)</td></tr><tr><td><code>bypassPermissions</code></td><td>auto</td><td>auto</td><td>auto</td></tr></tbody></table><h3 id="pattern-syntax" tabindex="-1">Pattern Syntax <a class="header-anchor" href="#pattern-syntax" aria-label="Permalink to &quot;Pattern Syntax&quot;">​</a></h3><p>Patterns follow the format <code>ToolName(argGlob)</code>:</p><ul><li><code>Bash(pnpm *)</code> -- Bash tool whose command starts with &quot;pnpm &quot;</li><li><code>Read(/src/**)</code> -- Read tool whose filePath is under /src/</li><li><code>Write(*)</code> -- Write tool with any argument</li><li><code>ToolName</code> -- Match any invocation of that tool (no argument constraint)</li></ul><h2 id="hook-system" tabindex="-1">Hook System <a class="header-anchor" href="#hook-system" aria-label="Permalink to &quot;Hook System&quot;">​</a></h2><p>The hook module (<code>src/hooks/</code>) provides a shell command-based lifecycle hook mechanism. Hooks receive JSON input on stdin and communicate results via exit codes.</p><h3 id="hook-events" tabindex="-1">Hook Events <a class="header-anchor" href="#hook-events" aria-label="Permalink to &quot;Hook Events&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Event</th><th>Timing</th><th>Purpose</th></tr></thead><tbody><tr><td><code>PreToolUse</code></td><td>Before tool execution</td><td>Validation, blocking, transformation</td></tr><tr><td><code>PostToolUse</code></td><td>After tool execution</td><td>Logging, auditing, notification</td></tr><tr><td><code>SessionStart</code></td><td>Session initialization</td><td>Setup, environment checks</td></tr><tr><td><code>Stop</code></td><td>Session termination</td><td>Cleanup, reporting</td></tr><tr><td><code>PreCompact</code></td><td>Before context compaction</td><td>Validation, logging (trigger: auto/manual)</td></tr><tr><td><code>PostCompact</code></td><td>After context compaction</td><td>Logging, notification (includes compact_summary)</td></tr></tbody></table><h3 id="exit-code-protocol" tabindex="-1">Exit Code Protocol <a class="header-anchor" href="#exit-code-protocol" aria-label="Permalink to &quot;Exit Code Protocol&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Code</th><th>Meaning</th></tr></thead><tbody><tr><td>0</td><td>Allow / proceed</td></tr><tr><td>2</td><td>Block / deny (stderr = reason)</td></tr><tr><td>other</td><td>Proceed with warning</td></tr></tbody></table><h3 id="hook-configuration" tabindex="-1">Hook Configuration <a class="header-anchor" href="#hook-configuration" aria-label="Permalink to &quot;Hook Configuration&quot;">​</a></h3><p>Hooks are configured as a <code>THooksConfig</code> object mapping events to arrays of <code>IHookGroup</code> entries. Each group has a <code>matcher</code> regex pattern (empty = match all) and an array of <code>IHookDefinition</code> commands. Hooks have a 10-second timeout.</p><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Extension</th><th>Base Class</th><th>Contract</th></tr></thead><tbody><tr><td>AI Provider</td><td><code>AbstractAIProvider</code></td><td>Implement <code>chat()</code>, <code>chatStream()</code></td></tr><tr><td>Tool</td><td><code>AbstractTool</code></td><td>Implement <code>execute()</code>, provide schema</td></tr><tr><td>Plugin</td><td><code>AbstractPlugin</code></td><td>Override lifecycle hooks</td></tr><tr><td>Module</td><td><code>AbstractModule</code></td><td>Implement <code>execute()</code></td></tr><tr><td>Executor</td><td><code>AbstractExecutor</code></td><td>Implement <code>execute()</code>, <code>executeStream()</code></td></tr><tr><td>Storage</td><td>Per-plugin interfaces</td><td>Implement storage adapter (memory, file, remote)</td></tr></tbody></table><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>All errors extend <code>RobotaError</code> with <code>code</code>, <code>category</code>, and <code>recoverable</code> properties:</p><table tabindex="0"><thead><tr><th>Error Class</th><th>Code</th><th>Category</th><th>Recoverable</th></tr></thead><tbody><tr><td><code>ConfigurationError</code></td><td><code>CONFIGURATION_ERROR</code></td><td>user</td><td>no</td></tr><tr><td><code>ValidationError</code></td><td><code>VALIDATION_ERROR</code></td><td>user</td><td>no</td></tr><tr><td><code>ProviderError</code></td><td><code>PROVIDER_ERROR</code></td><td>provider</td><td>yes</td></tr><tr><td><code>AuthenticationError</code></td><td><code>AUTHENTICATION_ERROR</code></td><td>user</td><td>no</td></tr><tr><td><code>RateLimitError</code></td><td><code>RATE_LIMIT_ERROR</code></td><td>provider</td><td>yes</td></tr><tr><td><code>NetworkError</code></td><td><code>NETWORK_ERROR</code></td><td>system</td><td>yes</td></tr><tr><td><code>ToolExecutionError</code></td><td><code>TOOL_EXECUTION_ERROR</code></td><td>system</td><td>no</td></tr><tr><td><code>ModelNotAvailableError</code></td><td><code>MODEL_NOT_AVAILABLE</code></td><td>user</td><td>no</td></tr><tr><td><code>CircuitBreakerOpenError</code></td><td><code>CIRCUIT_BREAKER_OPEN</code></td><td>system</td><td>yes</td></tr><tr><td><code>PluginError</code></td><td><code>PLUGIN_ERROR</code></td><td>system</td><td>no</td></tr><tr><td><code>StorageError</code></td><td><code>STORAGE_ERROR</code></td><td>system</td><td>yes</td></tr></tbody></table><p><code>ErrorUtils</code> provides <code>isRecoverable()</code>, <code>getErrorCode()</code>, <code>fromUnknown()</code>, and <code>wrapProviderError()</code>.</p><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>IAgent</code></td><td><code>AbstractAgent</code></td><td>abstract base</td><td><code>src/abstracts/abstract-agent.ts</code></td></tr><tr><td><code>IAgent</code></td><td><code>Robota</code></td><td>production</td><td><code>src/core/robota.ts</code></td></tr><tr><td><code>IAIProvider</code></td><td><code>AbstractAIProvider</code></td><td>abstract base</td><td><code>src/abstracts/abstract-ai-provider.ts</code></td></tr><tr><td><code>IExecutor</code></td><td><code>AbstractExecutor</code></td><td>abstract base</td><td><code>src/abstracts/abstract-executor.ts</code></td></tr><tr><td><code>IPluginContract</code>, <code>IPluginHooks</code></td><td><code>AbstractPlugin</code></td><td>abstract base</td><td><code>src/abstracts/abstract-plugin.ts</code></td></tr><tr><td><code>IToolWithEventService</code></td><td><code>AbstractTool</code></td><td>abstract base</td><td><code>src/abstracts/abstract-tool.ts</code></td></tr><tr><td><code>IModule</code>, <code>IModuleHooks</code></td><td><code>AbstractModule</code></td><td>abstract base</td><td><code>src/abstracts/abstract-module.ts</code></td></tr><tr><td><code>IWorkflowConverter</code></td><td><code>AbstractWorkflowConverter</code></td><td>abstract base</td><td><code>src/abstracts/abstract-workflow-converter.ts</code></td></tr><tr><td><code>IWorkflowValidator</code></td><td><code>AbstractWorkflowValidator</code></td><td>abstract base</td><td><code>src/abstracts/abstract-workflow-validator.ts</code></td></tr><tr><td><code>IEventService</code></td><td><code>AbstractEventService</code></td><td>abstract base</td><td><code>src/event-service/event-service.ts</code></td></tr><tr><td><code>IEventService</code></td><td><code>DefaultEventService</code></td><td>production (null object)</td><td><code>src/event-service/event-service.ts</code></td></tr><tr><td><code>IEventService</code></td><td><code>StructuredEventService</code></td><td>production</td><td><code>src/event-service/event-service.ts</code></td></tr><tr><td><code>IEventService</code></td><td><code>ObservableEventService</code></td><td>production</td><td><code>src/event-service/event-service.ts</code></td></tr><tr><td><code>IConversationHistory</code></td><td><code>ConversationHistory</code></td><td>production</td><td><code>src/managers/conversation-history-manager.ts</code></td></tr><tr><td><code>IConversationHistory</code></td><td><code>ConversationSession</code></td><td>production</td><td><code>src/managers/conversation-session.ts</code></td></tr><tr><td><code>IConversationService</code></td><td><code>ConversationService</code></td><td>production</td><td><code>src/services/conversation-service/index.ts</code></td></tr><tr><td><code>IToolManager</code></td><td><code>Tools</code></td><td>production</td><td><code>src/managers/tool-manager.ts</code></td></tr><tr><td><code>IAIProviderManager</code></td><td><code>AIProviders</code></td><td>production</td><td><code>src/managers/ai-provider-manager.ts</code></td></tr><tr><td><code>IPluginsManager</code></td><td><code>Plugins</code></td><td>production</td><td><code>src/managers/plugins.ts</code></td></tr><tr><td><code>ILogger</code></td><td><code>ConsoleLogger</code></td><td>production</td><td><code>src/utils/logger.ts</code></td></tr><tr><td><code>IEventHistoryModule</code></td><td><code>EventHistoryModule</code></td><td>production</td><td><code>src/services/history-module.ts</code></td></tr><tr><td><code>IEventHistoryModule</code></td><td><code>InMemoryHistoryStore</code></td><td>production</td><td><code>src/services/in-memory-history-store.ts</code></td></tr><tr><td><code>IEventEmitterMetrics</code></td><td><code>InMemoryEventEmitterMetrics</code></td><td>production</td><td><code>src/plugins/event-emitter/metrics.ts</code></td></tr><tr><td><code>ICacheStorage</code></td><td><code>MemoryCacheStorage</code></td><td>production</td><td><code>src/services/cache/memory-cache-storage.ts</code></td></tr></tbody></table><p>NOTE: <code>FunctionTool</code>, <code>ToolRegistry</code>, <code>OpenAPITool</code> moved to <code>@robota-sdk/agent-tools</code>. <code>MCPTool</code>, <code>RelayMcpTool</code> moved to <code>@robota-sdk/agent-tool-mcp</code>. Plugin storage implementations (ILogStorage, IUsageStorage, IPerformanceStorage, IHistoryStorage, etc.) moved to their respective <code>@robota-sdk/agent-plugin-*</code> packages.</p><h3 id="inheritance-chains-within-agent-core" tabindex="-1">Inheritance Chains (within agent-core) <a class="header-anchor" href="#inheritance-chains-within-agent-core" aria-label="Permalink to &quot;Inheritance Chains (within agent-core)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Base</th><th>Derived</th><th>Location</th><th>Notes</th></tr></thead><tbody><tr><td><code>AbstractAgent</code></td><td><code>Robota</code></td><td><code>src/core/robota.ts</code></td><td>Main facade</td></tr><tr><td><code>AbstractEventService</code></td><td><code>DefaultEventService</code></td><td><code>src/event-service/event-service.ts</code></td><td>Null object</td></tr><tr><td><code>AbstractEventService</code></td><td><code>StructuredEventService</code></td><td><code>src/event-service/event-service.ts</code></td><td>Owner-bound events</td></tr><tr><td><code>AbstractEventService</code></td><td><code>ObservableEventService</code></td><td><code>src/event-service/event-service.ts</code></td><td>RxJS integration</td></tr><tr><td><code>AbstractExecutor</code></td><td><code>LocalExecutor</code></td><td><code>src/executors/local-executor.ts</code></td><td>Local provider execution</td></tr><tr><td><code>AbstractPlugin</code></td><td><code>EventEmitterPlugin</code></td><td><code>src/plugins/event-emitter-plugin.ts</code></td><td>Event coordination</td></tr></tbody></table><p>NOTE: Tool implementations (<code>FunctionTool</code>, <code>OpenAPITool</code>) in <code>@robota-sdk/agent-tools</code> implement <code>IFunctionTool</code>/<code>ITool</code> directly without extending <code>AbstractTool</code>. Plugin implementations in <code>@robota-sdk/agent-plugin-*</code> extend <code>AbstractPlugin</code>.</p><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Adapter (Consumer Package)</th><th>Location</th></tr></thead><tbody><tr><td><code>AbstractAIProvider</code> (agent-core)</td><td><code>OpenAIProvider</code> (agent-provider-openai)</td><td><code>packages/agent-provider-openai/src/provider.ts</code></td></tr><tr><td><code>AbstractAIProvider</code> (agent-core)</td><td><code>AnthropicProvider</code> (agent-provider-anthropic)</td><td><code>packages/agent-provider-anthropic/src/provider.ts</code></td></tr><tr><td><code>AbstractAIProvider</code> (agent-core)</td><td><code>GoogleProvider</code> (agent-provider-google)</td><td><code>packages/agent-provider-google/src/provider.ts</code></td></tr><tr><td><code>AbstractAIProvider</code> (agent-core)</td><td><code>MockAIProvider</code> (agent-sessions)</td><td><code>packages/agent-sessions/examples/verify-offline.ts</code></td></tr><tr><td><code>AbstractExecutor</code> (agent-core)</td><td><code>SimpleRemoteExecutor</code> (agent-remote)</td><td><code>packages/agent-remote/src/client/remote-executor-simple.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><h3 id="current-coverage" tabindex="-1">Current Coverage <a class="header-anchor" href="#current-coverage" aria-label="Permalink to &quot;Current Coverage&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Layer</th><th>Test Files</th><th>Coverage</th></tr></thead><tbody><tr><td>Core (Robota)</td><td><code>robota.test.ts</code></td><td>Core flow</td></tr><tr><td>Executors</td><td><code>local-executor.test.ts</code></td><td>Local execution</td></tr><tr><td>Managers</td><td><code>agent-factory.test.ts</code>, <code>tool-manager.test.ts</code>, <code>conversation-history-manager.test.ts</code></td><td>Creation, tools, history</td></tr><tr><td>Plugins</td><td><code>event-emitter-plugin.test.ts</code></td><td>Event coordination</td></tr><tr><td>Services</td><td><code>event-service.test.ts</code>, <code>execution-service.test.ts</code></td><td>Events, execution</td></tr></tbody></table><h3 id="scenario-verification" tabindex="-1">Scenario Verification <a class="header-anchor" href="#scenario-verification" aria-label="Permalink to &quot;Scenario Verification&quot;">​</a></h3><ul><li>Command: <code>pnpm scenario:verify</code> (runs <code>examples/verify-offline.ts</code> with MockAIProvider)</li><li>Record: <code>examples/scenarios/offline-verify.record.json</code></li><li>Validates: agent creation, tool registration, conversation flow without network</li></ul><h3 id="coverage-gaps-improvement-targets" tabindex="-1">Coverage Gaps (Improvement Targets) <a class="header-anchor" href="#coverage-gaps-improvement-targets" aria-label="Permalink to &quot;Coverage Gaps (Improvement Targets)&quot;">​</a></h3><ul><li>Service edge cases: tool-execution-service, task-events, user-events</li><li>Utility tests: errors, validation, message-converter</li><li>NOTE: Plugin tests belong to <code>@robota-sdk/agent-plugin-*</code> packages. Tool tests belong to <code>@robota-sdk/agent-tools</code>.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><h3 id="production-2" tabindex="-1">Production (2) <a class="header-anchor" href="#production-2" aria-label="Permalink to &quot;Production (2)&quot;">​</a></h3><ul><li><code>jssha</code> — SHA hashing for content verification</li><li><code>zod</code> — Schema validation for tool parameters</li></ul><h3 id="key-peer-contracts" tabindex="-1">Key Peer Contracts <a class="header-anchor" href="#key-peer-contracts" aria-label="Permalink to &quot;Key Peer Contracts&quot;">​</a></h3><ul><li>Provider packages implement <code>AbstractAIProvider</code> and <code>IAIProvider</code></li><li><code>@robota-sdk/agent-sessions</code> consumes <code>Robota</code>, <code>runHooks</code>, <code>evaluatePermission</code>, <code>TUniversalMessage</code></li><li><code>@robota-sdk/agent-tools</code> consumes <code>AbstractTool</code>, <code>IFunctionTool</code>, <code>IToolWithEventService</code></li><li><code>@robota-sdk/agent-plugin-*</code> packages extend <code>AbstractPlugin</code></li><li><code>@robota-sdk/agent-team</code> consumes <code>Robota</code>, <code>IAgentConfig</code>, event services</li></ul>`,96)]))}const g=e(a,[["render",c]]);export{u as __pageData,g as default};
